def random_reaction(mood_name: str | None = None) -> str:
    """Return mood-specific compact art for the active mood."""

    if mood_name:
        reaction = MOOD_REACTIONS.get(mood_name.lower())
        if reaction:
            return reaction
    return MOOD_REACTIONS["caring"]
